import { parseDateToTimestamp } from './task05';

describe('parseDateToTimestamp', () => {
  it('parses ISO date to seconds', () => {
    const ts = parseDateToTimestamp('2024-01-15T10:30:00Z');
    expect(ts).toBeGreaterThan(0);
    expect(ts).toBeLessThan(Date.now() / 1000);
  });

  it('returns 0 for invalid input', () => {
    expect(parseDateToTimestamp('')).toBe(0);
    expect(parseDateToTimestamp('not-a-date')).toBe(0);
  });
});
